import {
  type FilePart,
  generateImage as generateImageWithImageModel,
  generateText,
  type ImagePart,
  type TextPart,
  tool,
} from "ai";
import { z } from "zod";
import {
  defineTool,
  type ToolRuntimeContext,
} from "@toolkit/lib/runtime";

type ImageMode = "edit" | "generate";

export function decodeBase64(data: string): Uint8Array {
  const dataUrlPrefixEnd = data.indexOf(";base64,");
  const encoded =
    data.startsWith("data:") && dataUrlPrefixEnd !== -1
      ? data.slice(dataUrlPrefixEnd + ";base64,".length)
      : data;
  const decoded = atob(encoded);
  return Uint8Array.from(decoded, (character) => character.charCodeAt(0));
}

async function filePartToBytes(
  file: FilePart,
  signal?: AbortSignal
): Promise<Uint8Array> {
  if (file.data instanceof URL) {
    const response = await fetch(file.data, { signal });
    return new Uint8Array(await response.arrayBuffer());
  }
  if (typeof file.data === "string") {
    return decodeBase64(file.data);
  }
  if (file.data instanceof ArrayBuffer) {
    return new Uint8Array(file.data);
  }
  return file.data;
}

function collectEditImageBytes(
  files: FilePart[],
  signal?: AbortSignal
): Promise<Uint8Array[]> {
  return Promise.all(files.map((file) => filePartToBytes(file, signal)));
}

function mediaExtension(mediaType: string): string {
  return mediaType.split("/")[1]?.split(";")[0] || "png";
}

export const generateImage = defineTool({
  id: "generate-image",
  needs: ["files.attachments", "files.previous", "media.write", "models.image"],
  createTool: (ctx: ToolRuntimeContext) =>
    tool({
      description: `Generate an image from a user-provided prompt.

The assistant may make small, neutral adjustments to improve clarity, composition, or technical quality, while strictly preserving the user's original intent, meaning, and message.

The assistant must not add new subjects, claims, branding, or alter the tone or intent of the prompt.
`,
      inputSchema: z.object({
        prompt: z
          .string()
          .describe(
            "The user's image prompt. The original intent, message, and meaning must remain unchanged. No new ideas, claims, or content may be introduced."
          ),
      }),
      // biome-ignore lint/complexity/noExcessiveCognitiveComplexity: Provider-specific image generation paths share setup and output handling.
      execute: async ({ prompt }, { abortSignal }) => {
        const [attachments, previousImages] = await Promise.all([
          ctx.files.attachments({ mediaTypes: ["image/"] }),
          ctx.files.previous({ kind: "image", limit: 1 }),
        ]);
        const imageInputs = [...previousImages, ...attachments];
        const mode: ImageMode = imageInputs.length > 0 ? "edit" : "generate";
        const imageGenerationModel = await ctx.models.imageGeneration({
          purpose: "generate-image",
        });

        if (imageGenerationModel.type === "language") {
          const userContent: Array<ImagePart | TextPart> = [];

          if (mode === "edit") {
            for (const image of imageInputs) {
              userContent.push({
                image: image.data,
                mediaType: image.mediaType,
                type: "image",
              });
            }
          }

          userContent.push({
            type: "text",
            text:
              mode === "edit"
                ? `Based on the provided image(s), ${prompt}`
                : `Generate an image: ${prompt}`,
          });

          const isGoogleModel =
            imageGenerationModel.modelId.startsWith("google/") ||
            imageGenerationModel.modelId.includes("gemini");
          const isOpenAIModel =
            imageGenerationModel.modelId.startsWith("openai/");

          const result = await generateText({
            abortSignal,
            messages: [{ role: "user", content: userContent }],
            model: imageGenerationModel.model,
            providerOptions: {
              ...(isGoogleModel && {
                google: {
                  responseModalities: ["TEXT", "IMAGE"],
                },
              }),
              ...(isOpenAIModel && {
                openai: {
                  modalities: ["text", "image"],
                },
              }),
            },
          });
          if (result.usage) {
            ctx.cost.addLLMCost(
              imageGenerationModel.modelId,
              result.usage,
              "generateImage-multimodal"
            );
          }

          const imageFile = result.files?.find((file) =>
            file.mediaType.startsWith("image/")
          );
          if (!imageFile) {
            throw new Error("No image generated by multimodal model");
          }

          const stored = await ctx.media.write({
            bytes: imageFile.uint8Array,
            filename: `generated-image-${Date.now()}.${mediaExtension(imageFile.mediaType)}`,
            mediaType: imageFile.mediaType,
          });

          return {
            imageUrl: stored.url,
            mediaType: stored.mediaType,
            prompt,
          };
        }

        const imageBytes =
          mode === "edit"
            ? await collectEditImageBytes(imageInputs, abortSignal)
            : [];
        const promptInput =
          mode === "edit" ? { text: prompt, images: imageBytes } : prompt;

        const result = await generateImageWithImageModel({
          abortSignal,
          model: imageGenerationModel.model,
          n: 1,
          prompt: promptInput,
        });

        const image = result.images[0];
        if (!image) {
          throw new Error("No image generated");
        }

        const stored = await ctx.media.write({
          bytes: image.uint8Array,
          filename: `generated-image-${Date.now()}.${mediaExtension(image.mediaType)}`,
          mediaType: image.mediaType,
        });
        if (result.usage) {
          ctx.cost.addLLMCost(
            imageGenerationModel.modelId,
            {
              inputTokens: result.usage.inputTokens,
              outputTokens: result.usage.outputTokens,
            },
            "generateImage-traditional"
          );
        }

        return {
          imageUrl: stored.url,
          mediaType: stored.mediaType,
          prompt,
        };
      },
      toModelOutput: ({ output }) => ({
        type: "json",
        value: {
          imageUrl: output.imageUrl,
          prompt: output.prompt,
        },
      }),
    }),
} as const);

"use client";

import { ImageOffIcon } from "lucide-react";
import { useState } from "react";
import { ImageActions, ImageModal } from "@ui/image-modal";
import type { TypelessToolPartFromTool } from "@toolkit/lib/tool-part";
import type { generateImage } from "./tool";

type GenerateImageRendererTool = TypelessToolPartFromTool<
  ReturnType<typeof generateImage.createTool>
>;

export function GenerateImageRenderer({
  tool,
}: {
  tool: GenerateImageRendererTool;
  messageId: string;
  isReadonly: boolean;
}) {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [failedImageUrl, setFailedImageUrl] = useState<string | null>(null);
  const imageUrl = tool.output?.imageUrl;
  const imageUnavailable = Boolean(imageUrl && failedImageUrl === imageUrl);

  if (tool.state === "input-available") {
    return (
      <div className="flex w-full flex-col items-center justify-center gap-4 rounded-lg border p-8">
        <div className="h-64 w-full animate-pulse rounded-lg bg-muted-foreground/20" />
        <div className="text-muted-foreground">
          Generating image: &quot;{tool.input.prompt}&quot;
        </div>
      </div>
    );
  }
  const output = tool.output;
  if (!output) {
    return (
      <div className="rounded-lg border p-4 text-muted-foreground text-sm">
        Couldn&apos;t generate image.
      </div>
    );
  }

  return (
    <>
      <div className="flex w-full flex-col gap-4 overflow-hidden rounded-lg border">
        <div className="group relative">
          {imageUnavailable ? (
            <div
              className="flex min-h-64 w-full flex-col items-center justify-center gap-2 bg-muted/30 text-muted-foreground"
              role="status"
            >
              <ImageOffIcon className="size-8" />
              <span>Generated image unavailable</span>
            </div>
          ) : (
            <>
              <button
                className="w-full cursor-pointer text-left"
                onClick={() => setDialogOpen(true)}
                type="button"
              >
                {/* biome-ignore lint/performance/noImgElement lint/a11y/noNoninteractiveElementInteractions: Next/Image isn't desired for dynamic external URLs; onError handles loading failure */}
                <img
                  alt={output.prompt}
                  className="h-auto w-full max-w-full"
                  height={512}
                  onError={() => setFailedImageUrl(imageUrl ?? null)}
                  src={output.imageUrl}
                  width={512}
                />
              </button>
              <ImageActions
                className="absolute top-2 right-2 opacity-0 transition-opacity group-hover:opacity-100"
                imageUrl={output.imageUrl}
              />
            </>
          )}
        </div>
        <div className="p-4 pt-0">
          <p className="text-muted-foreground text-sm">
            Generated from: &quot;{output.prompt}&quot;
          </p>
        </div>
      </div>

      <ImageModal
        imageName={output.prompt}
        imageUrl={output.imageUrl}
        isOpen={dialogOpen}
        onClose={() => setDialogOpen(false)}
      />
    </>
  );
}

"use client";

import { CopyIcon, DownloadIcon, ImageOffIcon, XIcon } from "lucide-react";
import { type MouseEvent, useEffect, useRef, useState } from "react";

interface ImageModalProps {
  imageName?: string;
  imageUrl: string;
  isOpen: boolean;
  onClose: () => void;
  showActions?: boolean;
}

async function copyImage(imageUrl: string): Promise<void> {
  const response = await fetch(imageUrl);
  if (!response.ok) {
    throw new Error("Failed to fetch image");
  }
  const blob = await response.blob();
  await navigator.clipboard.write([new ClipboardItem({ [blob.type]: blob })]);
}

async function downloadImage(imageUrl: string): Promise<void> {
  const response = await fetch(imageUrl);
  if (!response.ok) {
    throw new Error("Failed to fetch image");
  }
  const blob = await response.blob();
  const objectUrl = URL.createObjectURL(blob);
  const anchor = document.createElement("a");
  anchor.href = objectUrl;
  const extension = blob.type.split("/")[1]?.split(";")[0] || "png";
  anchor.download = `image-${Date.now()}.${extension}`;
  document.body.appendChild(anchor);
  anchor.click();
  anchor.remove();
  URL.revokeObjectURL(objectUrl);
}

function getCopyLabel(status: "copied" | "error" | "idle"): string {
  if (status === "copied") {
    return "Image copied";
  }
  if (status === "error") {
    return "Image copy failed";
  }
  return "Copy image";
}

export function ImageActions({
  className,
  imageUrl,
}: {
  className?: string;
  imageUrl: string;
}) {
  const [copyStatus, setCopyStatus] = useState<"copied" | "error" | "idle">(
    "idle"
  );
  const [downloadFailed, setDownloadFailed] = useState(false);

  const handleCopy = async (event: MouseEvent<HTMLButtonElement>) => {
    event.stopPropagation();
    try {
      await copyImage(imageUrl);
      setCopyStatus("copied");
    } catch {
      setCopyStatus("error");
    }
  };

  const handleDownload = async (event: MouseEvent<HTMLButtonElement>) => {
    event.stopPropagation();
    try {
      setDownloadFailed(false);
      await downloadImage(imageUrl);
    } catch {
      setDownloadFailed(true);
    }
  };

  const actionClassName =
    "inline-flex size-8 items-center justify-center rounded-md bg-black/60 text-white transition-colors hover:bg-black/80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-white";

  return (
    <div
      className={["flex items-center gap-1", className]
        .filter(Boolean)
        .join(" ")}
    >
      <button
        className={actionClassName}
        onClick={handleCopy}
        title={copyStatus === "copied" ? "Copied" : "Copy image"}
        type="button"
      >
        <CopyIcon aria-hidden="true" size={16} />
        <span aria-live="polite" className="sr-only">
          {getCopyLabel(copyStatus)}
        </span>
      </button>
      <button
        className={actionClassName}
        onClick={handleDownload}
        title={downloadFailed ? "Download failed" : "Download image"}
        type="button"
      >
        <DownloadIcon aria-hidden="true" size={16} />
        <span aria-live="polite" className="sr-only">
          {downloadFailed ? "Image download failed" : "Download image"}
        </span>
      </button>
    </div>
  );
}

export function ImageModal({
  isOpen,
  onClose,
  imageUrl,
  imageName,
  showActions = true,
}: ImageModalProps) {
  const dialogRef = useRef<HTMLDialogElement>(null);
  const [failedImageUrl, setFailedImageUrl] = useState<string | null>(null);
  const imageUnavailable = failedImageUrl === imageUrl;

  useEffect(() => {
    const dialog = dialogRef.current;
    if (!dialog || dialog.open === isOpen) {
      return;
    }
    if (isOpen) {
      dialog.showModal();
    } else {
      dialog.close();
    }
  }, [isOpen]);

  return (
    <dialog
      aria-label={imageName ?? "Image preview"}
      className="fixed inset-0 m-0 h-dvh max-h-none w-screen max-w-none border-0 bg-transparent p-0 backdrop:bg-black/70"
      onCancel={(event) => {
        event.preventDefault();
        onClose();
      }}
      ref={dialogRef}
    >
      <div className="relative flex h-full w-full items-center justify-center bg-black/30 p-6">
        <button
          aria-label="Close image preview"
          className="absolute inset-0 cursor-default"
          onClick={onClose}
          type="button"
        />
        <button
          aria-label="Close"
          className="absolute top-4 left-4 z-10 inline-flex size-9 items-center justify-center rounded-md bg-black/60 text-white transition-colors hover:bg-black/80 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-white"
          onClick={onClose}
          type="button"
        >
          <XIcon aria-hidden="true" size={20} />
        </button>
        {showActions && isOpen && !imageUnavailable && (
          <ImageActions
            className="absolute top-4 right-4 z-10"
            imageUrl={imageUrl}
          />
        )}
        {imageUnavailable ? (
          <span
            className="relative z-10 flex flex-col items-center gap-3 text-white"
            role="status"
          >
            <ImageOffIcon className="size-10" />
            <span>Image unavailable</span>
          </span>
        ) : (
          /* biome-ignore lint/performance/noImgElement lint/a11y/noNoninteractiveElementInteractions: Dynamic external images need a reusable loading-error state. */
          <img
            alt={imageName ?? "Expanded image"}
            className="relative z-10 max-h-[90vh] max-w-[90vw] object-contain"
            height={900}
            onError={() => setFailedImageUrl(imageUrl)}
            src={imageUrl}
            width={1600}
          />
        )}
      </div>
    </dialog>
  );
}
